mapper.select:
SELECT r.registration_id, r.project_id, p.project_name, r.lot_id, l.lot_name, l.lot_code, r.supplier_enterprise_id, r.supplier_name_snapshot, r.supplier_credit_code, r.contact_name, r.contact_phone, r.contact_email, r.registration_type, r.status, r.submit_time, r.qualified_result, r.qualified_time, r.qualified_by, r.reject_reason, r.cancel_time, r.cancel_reason, r.remark, r.version, r.create_time, r.update_time FROM t_bid_registration r INNER JOIN t_bid_project p ON p.project_id = r.project_id INNER JOIN t_bid_lot l ON l.lot_id = r.lot_id
r.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR r.supplier_name_snapshot LIKE CONCAT('%', #{queryForm.keyword}, '%') OR r.supplier_credit_code LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND r.project_id = #{queryForm.projectId}
AND r.lot_id = #{queryForm.lotId}
AND r.status = #{queryForm.status}
AND r.registration_type = #{queryForm.registrationType}
ORDER BY r.create_time DESC, r.registration_id DESC
